import axios from 'axios';

// Access API_BASE_URL from environment variables - FIXED URL
const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://localhost:8000/api/';
console.log('API_BASE_URL:', API_BASE_URL);

const api = axios.create({
    baseURL: API_BASE_URL,
    headers: {
        'Content-Type': 'application/json',
    },
    // Add timeout to prevent hanging requests
    timeout: 10000,
});

// Request interceptor to add JWT access token to headers
api.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('access_token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        // Add CORS headers for preflight requests
        config.headers['Accept'] = 'application/json';
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Response interceptor to handle token expiration and refresh
api.interceptors.response.use(
    (response) => response,
    async (error) => {
        const originalRequest = error.config;

        // Enhanced error logging
        console.error('API Error:', {
            status: error.response?.status,
            statusText: error.response?.statusText,
            data: error.response?.data,
            url: originalRequest?.url,
            method: originalRequest?.method
        });

        // If it's a 401 Unauthorized error and not a retry already
        // and the original request wasn't for token refresh itself
        if (error.response?.status === 401 && !originalRequest._retry && 
            !originalRequest.url.includes('/auth/refresh/') && 
            !originalRequest.url.includes('/token/refresh/')) {
            
            originalRequest._retry = true; // Mark this request as retried
            const refreshToken = localStorage.getItem('refresh_token');

            if (refreshToken) {
                try {
                    // Attempt to refresh the token - FIXED URL
                    const response = await axios.post(`${API_BASE_URL}auth/refresh/`, {
                        refresh: refreshToken,
                    }, {
                        headers: {
                            'Content-Type': 'application/json',
                        }
                    });

                    // Update tokens in localStorage
                    localStorage.setItem('access_token', response.data.access);
                    if (response.data.refresh) {
                        localStorage.setItem('refresh_token', response.data.refresh);
                    }

                    // Update the Authorization header for the Axios instance and the original request
                    api.defaults.headers.common['Authorization'] = `Bearer ${response.data.access}`;
                    originalRequest.headers['Authorization'] = `Bearer ${response.data.access}`;

                    // Retry the original request with the new access token
                    return api(originalRequest);
                } catch (refreshError) {
                    // If refresh token fails (e.g., refresh token expired or invalid)
                    console.error("Refresh token failed:", refreshError.response?.data || refreshError.message);
                    
                    // Clear all tokens and redirect to login
                    localStorage.removeItem('access_token');
                    localStorage.removeItem('refresh_token');
                    localStorage.removeItem('user_data');
                    delete api.defaults.headers.common['Authorization'];
                    
                    // Only redirect if not already on login page
                    if (window.location.pathname !== '/login') {
                        window.location.href = '/login';
                    }
                    
                    return Promise.reject(refreshError);
                }
            } else {
                // No refresh token available, clear and redirect to login
                localStorage.removeItem('access_token');
                localStorage.removeItem('refresh_token');
                localStorage.removeItem('user_data');
                delete api.defaults.headers.common['Authorization'];
                
                if (window.location.pathname !== '/login') {
                    window.location.href = '/login';
                }
            }
        }

        // Handle network errors
        if (!error.response) {
            console.error('Network error:', error.message);
            // You might want to show a network error message to the user
        }

        return Promise.reject(error);
    }
);

export default api;
